19: type Level uint32
20: 
21: type LevelFunc = func(ctx interface{}, msg interface{}, keyValuePairs ...interface{})
22: 
23: var redacted = &Hook{
24: 	AcceptedLevels: logrus.AllLevels,
25: 	RedactionList: []string{
26: 		// Keys from the config
27: 		"(ApiKey:\")[\\w]*",
28: 		"(Secret:\")[\\w]*",
29: 		"(Spotify.*ID:\")[\\w]*",
30: 		"(PasswordEncryptionKey:[\\s]*\")[^\"]*",
31: 		"(ReverseProxyUserHeader:[\\s]*\")[^\"]*",
32: 		"(ReverseProxyWhitelist:[\\s]*\")[^\"]*",
33: 		"(MetricsPath:[\\s]*\")[^\"]*",
34: 		"(DevAutoCreateAdminPassword:[\\s]*\")[^\"]*",
35: 		"(DevAutoLoginUsername:[\\s]*\")[^\"]*",
36: 
37: 		// UI appConfig
38: 		"(subsonicToken:)[\\w]+(\\s)",
39: 		"(subsonicSalt:)[\\w]+(\\s)",
40: 		"(token:)[^\\s]+",
41: 
42: 		// Subsonic query params
43: 		"([^\\w]t=)[\\w]+",
44: 		"([^\\w]s=)[^&]+",
45: 		"([^\\w]p=)[^&]+",
46: 		"([^\\w]jwt=)[^&]+",
47: 
48: 		// External services query params
49: 		"([^\\w]api_key=)[\\w]+",
50: 	},
51: }
52: 
53: const (
54: 	LevelFatal = Level(logrus.FatalLevel)
55: 	LevelError = Level(logrus.ErrorLevel)
56: 	LevelWarn  = Level(logrus.WarnLevel)
57: 	LevelInfo  = Level(logrus.InfoLevel)
58: 	LevelDebug = Level(logrus.DebugLevel)
59: 	LevelTrace = Level(logrus.TraceLevel)
60: )
61: 
62: type contextKey string
63: 
64: const loggerCtxKey = contextKey("logger")
65: 
66: type levelPath struct {
67: 	path  string
68: 	level Level
69: }
70: 
71: var (
72: 	currentLevel  Level
73: 	defaultLogger = logrus.New()
74: 	logSourceLine = false
75: 	rootPath      string
76: 	logLevels     []levelPath
77: )
78: 
79: // SetLevel sets the global log level used by the simple logger.
80: func SetLevel(l Level) {
81: 	currentLevel = l
82: 	defaultLogger.Level = logrus.TraceLevel
83: 	logrus.SetLevel(logrus.Level(l))
84: }
85: 
86: func SetLevelString(l string) {
87: 	level := levelFromString(l)
88: 	SetLevel(level)
89: }
90: 
91: func levelFromString(l string) Level {
92: 	envLevel := strings.ToLower(l)
93: 	var level Level
94: 	switch envLevel {
95: 	case "fatal":
96: 		level = LevelFatal
97: 	case "error":
98: 		level = LevelError
99: 	case "warn":
100: 		level = LevelWarn
101: 	case "debug":
102: 		level = LevelDebug
103: 	case "trace":
104: 		level = LevelTrace
105: 	default:
106: 		level = LevelInfo
107: 	}
108: 	return level
109: }
110: 
111: // SetLogLevels sets the log levels for specific paths in the codebase.
112: func SetLogLevels(levels map[string]string) {
113: 	logLevels = nil
114: 	for k, v := range levels {
115: 		logLevels = append(logLevels, levelPath{path: k, level: levelFromString(v)})
116: 	}
117: 	sort.Slice(logLevels, func(i, j int) bool {
118: 		return logLevels[i].path > logLevels[j].path
119: 	})
120: }
121: 
122: func SetLogSourceLine(enabled bool) {
123: 	logSourceLine = enabled
124: }
125: 
126: func SetRedacting(enabled bool) {
127: 	if enabled {
128: 		defaultLogger.AddHook(redacted)
129: 	}
130: }
131: 
132: func SetOutput(w io.Writer) {
133: 	if runtime.GOOS == "windows" {
134: 		w = CRLFWriter(w)
135: 	}
136: 	defaultLogger.SetOutput(w)
137: }
138: 
139: // Redact applies redaction to a single string
140: func Redact(msg string) string {
141: 	r, _ := redacted.redact(msg)
142: 	return r
143: }
144: 
145: func NewContext(ctx context.Context, keyValuePairs ...interface{}) context.Context {
146: 	if ctx == nil {
147: 		ctx = context.Background()
148: 	}
149: 
150: 	logger, ok := ctx.Value(loggerCtxKey).(*logrus.Entry)
151: 	if !ok {
152: 		logger = createNewLogger()
153: 	}
154: 	logger = addFields(logger, keyValuePairs)
155: 	ctx = context.WithValue(ctx, loggerCtxKey, logger)
156: 
157: 	return ctx
158: }
159: 
160: func SetDefaultLogger(l *logrus.Logger) {
161: 	defaultLogger = l
162: }
163: 
164: func CurrentLevel() Level {
165: 	return currentLevel
166: }
167: 
168: // IsGreaterOrEqualTo returns true if the caller's current log level is equal or greater than the provided level.
169: func IsGreaterOrEqualTo(level Level) bool {
170: 	return shouldLog(level, 2)
171: }
172: 
173: func Fatal(args ...interface{}) {
174: 	log(LevelFatal, args...)
175: 	os.Exit(1)
176: }
177: 
178: func Error(args ...interface{}) {
179: 	log(LevelError, args...)
180: }
181: 
182: func Warn(args ...interface{}) {
183: 	log(LevelWarn, args...)
184: }
185: 
186: func Info(args ...interface{}) {
187: 	log(LevelInfo, args...)
188: }
189: 
190: func Debug(args ...interface{}) {
191: 	log(LevelDebug, args...)
192: }
193: 
194: func Trace(args ...interface{}) {
195: 	log(LevelTrace, args...)
196: }
197: 
198: func log(level Level, args ...interface{}) {
199: 	if !shouldLog(level, 3) {
200: 		return
201: 	}
202: 	logger, msg := parseArgs(args)
203: 	logger.Log(logrus.Level(level), msg)
204: }
205: 
206: func shouldLog(requiredLevel Level, skip int) bool {
207: 	if currentLevel >= requiredLevel {
208: 		return true
209: 	}
210: 	if len(logLevels) == 0 {
211: 		return false
212: 	}
213: 
214: 	_, file, _, ok := runtime.Caller(skip)
215: 	if !ok {
216: 		return false
217: 	}
218: 
219: 	file = strings.TrimPrefix(file, rootPath)
220: 	for _, lp := range logLevels {
221: 		if strings.HasPrefix(file, lp.path) {
222: 			return lp.level >= requiredLevel
223: 		}
224: 	}
225: 	return false
226: }
227: 
228: func parseArgs(args []interface{}) (*logrus.Entry, string) {
229: 	var l *logrus.Entry
230: 	var err error
231: 	if args[0] == nil {
232: 		l = createNewLogger()
233: 		args = args[1:]
234: 	} else {
235: 		l, err = extractLogger(args[0])
236: 		if err != nil {
237: 			l = createNewLogger()
238: 		} else {
239: 			args = args[1:]
240: 		}
241: 	}
242: 	if len(args) > 1 {
243: 		kvPairs := args[1:]
244: 		l = addFields(l, kvPairs)
245: 	}
246: 	if logSourceLine {
247: 		_, file, line, ok := runtime.Caller(3)
248: 		if !ok {
249: 			file = "???"
250: 			line = 0
251: 		}
252: 		//_, filename := path.Split(file)
253: 		//l = l.WithField("filename", filename).WithField("line", line)
254: 		l = l.WithField(" source", fmt.Sprintf("file://%s:%d", file, line))
255: 	}
256: 
257: 	switch msg := args[0].(type) {
258: 	case error:
259: 		return l, msg.Error()
260: 	case string:
261: 		return l, msg
262: 	}
263: 
264: 	return l, ""
265: }
266: 
267: func addFields(logger *logrus.Entry, keyValuePairs []interface{}) *logrus.Entry {
268: 	for i := 0; i < len(keyValuePairs); i += 2 {
269: 		switch name := keyValuePairs[i].(type) {
270: 		case error:
271: 			logger = logger.WithField("error", name.Error())
272: 		case string:
273: 			if i+1 >= len(keyValuePairs) {
274: 				logger = logger.WithField(name, "!!!!Invalid number of arguments in log call!!!!")
275: 			} else {
276: 				switch v := keyValuePairs[i+1].(type) {
277: 				case time.Duration:
278: 					logger = logger.WithField(name, ShortDur(v))
279: 				case fmt.Stringer:
280: 					vOf := reflect.ValueOf(v)
281: 					if vOf.Kind() == reflect.Pointer && vOf.IsNil() {
282: 						logger = logger.WithField(name, "nil")
283: 					} else {
284: 						logger = logger.WithField(name, v.String())
285: 					}
286: 				default:
287: 					logger = logger.WithField(name, v)
288: 				}
289: 			}
290: 		}
291: 	}
292: 	return logger
293: }
294: 
295: func extractLogger(ctx interface{}) (*logrus.Entry, error) {
296: 	switch ctx := ctx.(type) {
297: 	case *logrus.Entry:
298: 		return ctx, nil
299: 	case context.Context:
300: 		logger := ctx.Value(loggerCtxKey)
301: 		if logger != nil {
302: 			return logger.(*logrus.Entry), nil
303: 		}
304: 		return extractLogger(NewContext(ctx))
305: 	case *http.Request:
306: 		return extractLogger(ctx.Context())
307: 	}
308: 	return nil, errors.New("no logger found")
309: }
310: 
311: func createNewLogger() *logrus.Entry {
312: 	//logrus.SetFormatter(&logrus.TextFormatter{ForceColors: true, DisableTimestamp: false, FullTimestamp: true})
313: 	//l.Formatter = &logrus.TextFormatter{ForceColors: true, DisableTimestamp: false, FullTimestamp: true}
314: 	logger := logrus.NewEntry(defaultLogger)
315: 	return logger
316: }
317: 
318: func init() {
319: 	defaultLogger.Level = logrus.TraceLevel
320: 	_, file, _, ok := runtime.Caller(0)
321: 	if !ok {
322: 		return
323: 	}
324: 	rootPath = strings.TrimSuffix(file, "log/log.go")
325: }
