9: func ShortDur(d time.Duration) string {
10: 	var s string
11: 	switch {
12: 	case d > time.Hour:
13: 		s = d.Round(time.Minute).String()
14: 	case d > time.Minute:
15: 		s = d.Round(time.Second).String()
16: 	case d > time.Second:
17: 		s = d.Round(10 * time.Millisecond).String()
18: 	case d > time.Millisecond:
19: 		s = d.Round(100 * time.Microsecond).String()
20: 	default:
21: 		s = d.String()
22: 	}
23: 	s = strings.TrimSuffix(s, "0s")
24: 	return strings.TrimSuffix(s, "0m")
25: }
26: 
27: func CRLFWriter(w io.Writer) io.Writer {
28: 	return &crlfWriter{w: w}
29: }
30: 
31: type crlfWriter struct {
32: 	w        io.Writer
33: 	lastByte byte
34: }
35: 
36: func (cw *crlfWriter) Write(p []byte) (int, error) {
37: 	var written int
38: 	for _, b := range p {
39: 		if b == '\n' && cw.lastByte != '\r' {
40: 			if _, err := cw.w.Write([]byte{'\r'}); err != nil {
41: 				return written, err
42: 			}
43: 		}
44: 		if _, err := cw.w.Write([]byte{b}); err != nil {
45: 			return written, err
46: 		}
47: 		written++
48: 		cw.lastByte = b
49: 	}
50: 	return written, nil
51: }
