28: 			name:           "definedAcceptedLevels",
29: 			acceptedLevels: []logrus.Level{logrus.InfoLevel},
30: 			expected:       []logrus.Level{logrus.InfoLevel},
31: 			description:    "Logrus Info level expected, but did not receive that.",
32: 		},
33: 	}
34: 
35: 	for _, test := range tests {
36: 		fn := func(t *testing.T) {
37: 			h.AcceptedLevels = test.acceptedLevels
