46: type levelThresholdTest struct {
47: 	name        string
48: 	level       logrus.Level
49: 	expected    []logrus.Level
50: 	description string
51: }
52: 
53: // levelThreshold returns a []logrus.Level including all levels
54: // above and including the level given. If the provided level does not exit,
55: // an empty slice is returned.
56: func levelThreshold(l logrus.Level) []logrus.Level {
57: 	//nolint
58: 	if l < 0 || int(l) > len(logrus.AllLevels) {
59: 		return []logrus.Level{}
60: 	}
61: 	return logrus.AllLevels[:l+1]
62: }
63: 
64: func TestLevelThreshold(t *testing.T) {
65: 	tests := []levelThresholdTest{
66: 		{
67: 			name:        "unknownLogLevel",
68: 			level:       logrus.Level(100),
69: 			expected:    []logrus.Level{},
70: 			description: "An empty Level slice was expected but was not returned",
71: 		},
72: 		{
73: 			name:        "errorLogLevel",
74: 			level:       logrus.ErrorLevel,
75: 			expected:    []logrus.Level{logrus.PanicLevel, logrus.FatalLevel, logrus.ErrorLevel},
76: 			description: "The panic, fatal, and error levels were expected but were not returned",
77: 		},
78: 	}
79: 
80: 	for _, test := range tests {
81: 		fn := func(t *testing.T) {
82: 			levels := levelThreshold(test.level)
83: 			assert.Equal(t, test.expected, levels, test.description)
84: 		}
85: 
86: 		t.Run(test.name, fn)
87: 	}
88: }
