119: 			redactionList: []string{"William"},
120: 			logFields:     logrus.Fields{"Description": "His name is William"},
121: 			expected:      logrus.Fields{"Description": "His name is [REDACTED]"},
122: 			description:   "William should have been redacted, but was not.",
123: 		},
124: 		{
125: 			name:          "map value",
126: 			redactionList: []string{"William"},
127: 			logFields:     logrus.Fields{"Description": map[string]string{"name": "His name is William"}},
128: 			expected:      logrus.Fields{"Description": "map[name:His name is [REDACTED]]"},
129: 			description:   "William should have been redacted, but was not.",
130: 		},
131: 	}
