			Expect(hook.LastEntry().Data["key1"]).To(Equal(t.String()))
		})
		It("logs nil fmt.Stringer as nil", func() {
			var t *time.Time
			Error("Simple Message", "key1", t)
			Expect(hook.LastEntry().Data["key1"]).To(Equal("nil"))
		})
	})

